export const getGetYouUrl = (params?: GetYouParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : String(value));
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/you?${stringifiedParams}`
    : `/api/you`;
};

/**
 * This resource provides basic information about an authenticated user based on the session cookie presence.
 * @summary Gets information about authenticated user.
 */
export const getYou = async (
  params?: GetYouParams,
  options?: RequestInit,
): Promise<getYouResponse> => {
  return customAxiosInstance<getYouResponse>(getGetYouUrl(params), {
    ...options,
    method: "GET",
  });
};

export const getGetYouQueryKey = (params?: GetYouParams) => {
  return [`/api/you`, ...(params ? [params] : [])] as const;
};

export const getGetYouQueryOptions = <
  TData = Awaited<ReturnType<typeof getYou>>,
  TError = GetYou401 | GetYou403 | GetYou500,
>(
  params?: GetYouParams,
  options?: {
    query?: Partial<
      UseQueryOptions<Awaited<ReturnType<typeof getYou>>, TError, TData>
    >;
  },
) => {
  const { query: queryOptions } = options ?? {};

  const queryKey = queryOptions?.queryKey ?? getGetYouQueryKey(params);

  const queryFn: QueryFunction<Awaited<ReturnType<typeof getYou>>> = ({
    signal,
  }) => getYou(params, { signal });

  return { queryKey, queryFn, ...queryOptions } as UseQueryOptions<
    Awaited<ReturnType<typeof getYou>>,
    TError,
    TData
  > & { queryKey: DataTag<QueryKey, TData> };
};

